export function createWordStats(wordId: string, profileId: string, overrides?: Partial<WordStats>): WordStats {
  return {
    id: `stats-${wordId}`,
    wordId,
    profileId,
    lastAsked: null,
    timesAsked: 0,
    timesWrong: 0,
    timesStruggledRight: 0,
    timesEasyRight: 0,
    consecutiveCorrect: 0,
    currentBucket: 'new',
    nextReviewDate: new Date(),
    difficultyScore: 0.5,
    techniqueHistory: [],
    ...overrides,
  };
}
